using namespace std;

class Solution {
public:
    string smallestEquivalentString(string s1, string s2, string baseStr) {
        vector<int> parent(26);
        vector<int> rank(26);
        vector<char> min_char(26);

        for (int i = 0; i < 26; ++i) {
            parent[i] = i;
            rank[i] = 1;
            min_char[i] = 'a' + i;
        }

        for (int i = 0; i < s1.size(); ++i) {
            char c1 = s1[i];
            char c2 = s2[i];
            int idx1 = c1 - 'a';
            int idx2 = c2 - 'a';

            // Find root of idx1
            int root1 = idx1;
            while (parent[root1] != root1) {
                root1 = parent[root1];
            }

            // Find root of idx2
            int root2 = idx2;
            while (parent[root2] != root2) {
                root2 = parent[root2];
            }

            if (root1 != root2) {
                if (rank[root1] > rank[root2]) {
                    swap(root1, root2);
                }
                parent[root1] = root2;
                if (rank[root1] == rank[root2]) {
                    rank[root2]++;
                }
                if (min_char[root1] < min_char[root2]) {
                    min_char[root2] = min_char[root1];
                }
            }
        }

        string result;
        for (char c : baseStr) {
            int idx = c - 'a';
            int root = idx;
            while (parent[root] != root) {
                root = parent[root];
            }
            result += min_char[root];
        }

        return result;
    }
};

